import React from "react";

function Home() {
  return (
    <div style={{ textAlign: "center", marginTop: "100px" }}>
      <img
        src="/profile.jpg"
        alt="profile"
        style={{ width: "150px", borderRadius: "50%" }}
      />
      <h1>Your Name</h1>
      <h3>Web Developer</h3>
      <p>This is my portfolio website.</p>
    </div>
  );
}

export default Home;
